package com.nt.main;

import org.springframework.context.support.ClassPathXmlApplicationContext;
import com.nt.sbeans.WishMessageGenerator;

public class DependencyManagementTest {
    public static void main(String[] args) {
        try (ClassPathXmlApplicationContext ctx =
                 new ClassPathXmlApplicationContext("com/nt/cfgs/applicationContext.xml")) {
            WishMessageGenerator generator = ctx.getBean("wmg", WishMessageGenerator.class);
            String result = generator.showWishMessage("raja");
            System.out.println(result);
        }
    }
}
```

Alternative if you must use filesystem loading:
- Ensure the startup working directory contains the path `src/com/nt/cfgs/applicationContext.xml` (or use the absolute path to the file).
